member.example:
Bind a relay command to a Slider's value change using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SliderCommandBinder _onVolumeChanged;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnVolumeChanged(float volume) { }
    }


Bind a relay command in code, receiving the slider value as an int.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Slider _slider;
        
        private SliderCommandBinder VolumeCommand => new(_slider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnVolumeChanged(int volume) { }
    }

Bind a relay command to a Slider's value change using a MonoBinder component assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SliderCommandMonoBinder _onVolumeChanged;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnVolumeChanged(float volume) { }
        
        [RelayCommand]
        private void OnVolumeChanged(int volume) { }
    }

Bind a relay command with one additional parameter to a Slider's value change.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SliderCommandBinder<string> _onVolumeChanged;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnVolumeChanged(float volume, string channel) { }
    }

Bind a relay command with one additional parameter using a MonoBinder component.
Because SliderCommandMonoBinder<T> is abstract, a concrete derived class is required.

    [AddComponentMenu("MyGame/Binders/ChannelVolumeCommandBinder")]
    public sealed class ChannelVolumeCommandMonoBinder : SliderCommandMonoBinder<string> { }
    
    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ChannelVolumeCommandMonoBinder _onVolumeChanged;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnVolumeChanged(float volume, string channel) { }
    }

